const intent = $('Execute Workflow Trigger').first().json || {};

// If we don't have both hours and preference, ask for them
if (!intent.tourist_hours || !intent.tourist_preference) {
  let question = "🌴 Welcome to Kochi! I'll build you a personalised metro day trip.\n\n";

  if (!intent.tourist_hours && !intent.tourist_preference) {
    question += "Quick question — how long do you have and what do you enjoy?\n\nReply like: _full day, history and food_ or _4 hours, shopping_";
  } else if (!intent.tourist_hours) {
    question += "How long do you have — half day (3-4 hrs) or full day (6+ hrs)?";
  } else {
    question += "What do you enjoy most?\n1️⃣ History & Heritage\n2️⃣ Food & Local Markets\n3️⃣ Shopping\n4️⃣ Mix of everything";
  }

  return [{ json: { result: question } }];
}

// We have both — build the itinerary
const ATTRACTIONS = {
  "Aluva": {
    name: "Aluva Manapuram & Sivarathri Festival Grounds",
    description: "Sacred river bank, historic Shiva temple",
    walk: "5 min",
    best_time: "morning",
    category: "history",
    duration: 45
  },
  "Kalamassery": {
    name: "Cochin Special Economic Zone",
    description: "Modern Kerala industrial hub",
    walk: "10 min",
    best_time: "morning",
    category: "mix",
    duration: 30
  },
  "Edapally": {
    name: "LuLu Mall",
    description: "Largest mall in India — food court, shops, entertainment",
    walk: "5 min",
    best_time: "afternoon",
    category: "shopping",
    duration: 120
  },
  "Palarivattom": {
    name: "Palarivattom Junction & Local Markets",
    description: "Buzzing local market, street food heaven",
    walk: "2 min",
    best_time: "evening",
    category: "food",
    duration: 60
  },
  "JLN Stadium": {
    name: "Jawaharlal Nehru Stadium",
    description: "Iconic sports venue and surrounding park",
    walk: "3 min",
    best_time: "morning",
    category: "mix",
    duration: 30
  },
  "MG Road": {
    name: "Marine Drive",
    description: "Iconic Kochi waterfront promenade, perfect for evening walks",
    walk: "5 min",
    best_time: "evening",
    category: "sightseeing",
    duration: 60
  },
  "Ernakulam South": {
    name: "Jew Town & Mattancherry Palace",
    description: "500-year-old spice market, Dutch Palace murals, antique shops",
    walk: "ferry 10 min + 5 min walk",
    best_time: "morning",
    category: "history",
    duration: 120
  },
  "Vyttila": {
    name: "Vyttila Mobility Hub & Local Backwater Views",
    description: "Kerala's largest transport hub with backwater views",
    walk: "2 min",
    best_time: "afternoon",
    category: "mix",
    duration: 30
  },
  "MG Road_food": {
    station: "MG Road",
    name: "Kayees Rahmathulla Hotel",
    description: "Legendary Kochi biryani since 1947 — a must-eat",
    walk: "8 min",
    best_time: "lunch",
    category: "food",
    duration: 45
  },
  "Kaloor": {
    name: "Kaloor International Stadium & FC Kerala",
    description: "Football mad Kochi — stadium tours available",
    walk: "5 min",
    best_time: "afternoon",
    category: "mix",
    duration: 45
  }
};

// Select stops based on preference and hours
const pref = intent.tourist_preference.toLowerCase();
const hours = intent.tourist_hours.toLowerCase();
const maxStops = hours === "full" ? 5 : 3;
const maxMins = hours === "full" ? 360 : 180;

// Filter and score attractions
let candidates = Object.entries(ATTRACTIONS).filter(([key, a]) => {
  if (pref === "mix") return true;
  if (pref === "history") return a.category === "history" || a.category === "mix";
  if (pref === "food") return a.category === "food" || a.category === "mix";
  if (pref === "shopping") return a.category === "shopping" || a.category === "mix";
  return true;
});

// Pick stops that fit in the time budget
let selectedStops = [];
let totalMins = 0;

// Always start from Aluva (northernmost, logical start)
const startStation = "Aluva";

// Build a logical south-to-north or north-to-south route
const LINE_ORDER = ["Aluva","Pulinchodu","Companypady","Ambattukavu","Muttom",
  "Kalamassery","Cochin University","Pathadipalam","Edapally","Changampuzha Park",
  "Palarivattom","JLN Stadium","Kaloor","Town Hall","MG Road","Maharajas College",
  "Ernakulam South","Kadavanthra","Elamkulam","Vyttila","Thykoodam","Pettah",
  "Vadakkekotta","SN Junction","Tripunithura"];

// Sort candidates by line order for logical route
candidates.sort((a, b) => {
  const stationA = a[1].station ?? a[0].replace("_food","").replace("_alt","");
  const stationB = b[1].station ?? b[0].replace("_food","").replace("_alt","");
  return LINE_ORDER.indexOf(stationA) - LINE_ORDER.indexOf(stationB);
});

for (const [key, attraction] of candidates) {
  if (selectedStops.length >= maxStops) break;
  if (totalMins + attraction.duration + 5 > maxMins) continue;

  const stationName = attraction.station ?? key.replace("_food","").replace("_alt","");
  selectedStops.push({
    station: stationName,
    ...attraction
  });
  totalMins += attraction.duration + 5; // 5 min metro between stops
}

if (selectedStops.length === 0) {
  return [{ json: { result: "I couldn't find matching attractions. Try: _mix of everything_ or _full day_" } }];
}

// Calculate times starting from 9 AM
let currentMins = 9 * 60;
let itinerary = [];
let mapStops = [];
let previousStation = startStation;

for (const stop of selectedStops) {
  const stopsCount = Math.abs(
    LINE_ORDER.indexOf(stop.station) - LINE_ORDER.indexOf(previousStation)
  );
  const transitMins = stopsCount * 2;
  currentMins += transitMins;

  const arriveH = Math.floor(currentMins / 60);
  const arriveM = currentMins % 60;
  const arriveStr = `${arriveH}:${String(arriveM).padStart(2,"0")}`;

  const leaveH = Math.floor((currentMins + stop.duration) / 60);
  const leaveM = (currentMins + stop.duration) % 60;
  const leaveStr = `${leaveH}:${String(leaveM).padStart(2,"0")}`;

  itinerary.push({
    station: stop.station,
    name: stop.name,
    description: stop.description,
    walk: stop.walk,
    arrive: arriveStr,
    leave: leaveStr,
    duration: stop.duration
  });

  mapStops.push(encodeURIComponent(stop.station + " Metro Station Kochi"));
  currentMins += stop.duration;
  previousStation = stop.station;
}

// Build reply message
const emoji = { history: "🏛", food: "🍛", shopping: "🛍", mix: "🌴", sightseeing: "🌊" };

let reply = `🌴 *Your Kochi Metro Day Trip*\n`;
reply += `${hours === "full" ? "Full Day" : "Half Day"} · ${pref === "mix" ? "Best of Kochi" : pref.charAt(0).toUpperCase() + pref.slice(1)}\n\n`;

for (let i = 0; i < itinerary.length; i++) {
  const stop = itinerary[i];
  const cat = ATTRACTIONS[stop.station]?.category ?? "mix";
  reply += `${emoji[cat] ?? "📍"} *${stop.arrive} — ${stop.name}*\n`;
  reply += `📍 ${stop.station} Metro · 🚶 ${stop.walk}\n`;
  reply += `_${stop.description}_\n`;
  if (i < itinerary.length - 1) reply += `\n`;
}

const totalFareEstimate = selectedStops.length * 20; // rough average

reply += `\n💳 Estimated metro fare: ₹${totalFareEstimate}\n`;
reply += `⏱ Total time: ~${Math.round(totalMins / 60 * 10) / 10} hours\n\n`;

const mapsUrl = `https://www.google.com/maps/dir/${mapStops.join("/")}`;
reply += `🗺 Full route on Maps:\n${mapsUrl}\n\n`;
reply += `_Tap any station name to explore more · Reply to replan_`;

return [{ json: { result: reply } }];
